function renderMonthCalendar() { const y=calendarCursor.getFullYear(),m=calendarCursor.getMonth(),first=new Date(y,m,1),offset=(first.getDay()+6)%7,days=new Date(y,m+1,0).getDate(),previous=new Date(y,m,0).getDate(); $('#monthLabel').textContent=first.toLocaleDateString('fr-FR',{month:'long',year:'numeric'}); const cells=[]; for(let i=0;i<42;i++){let d,muted=false;if(i<offset){d=new Date(y,m-1,previous-offset+i+1);muted=true}else if(i>=offset+days){d=new Date(y,m+1,i-offset-days+1);muted=true}else d=new Date(y,m,i-offset+1);const date=dateKey(d),items=state.agenda.filter(a=>a.date===date);cells.push(`<div class="month-day ${muted?'muted':''} ${date===localDate()?'today':''}"><b>${d.getDate()}</b>${items.map(a=>`<button class="month-event ${a.kind} ${a.completed?'completed':''}" data-delete-agenda="${a.id}" title="${a.completed?'Séance terminée · cliquer pour supprimer':'Cliquer pour supprimer'}">${a.time} ${escapeHtml(a.title)} ${a.completed?'✓':'×'}</button>`).join('')}</div>`)} $('#monthCalendar').innerHTML=cells.join(''); }
function renderExerciseLibrary() { const term=$('#exerciseSearch').value.trim().toLocaleLowerCase('fr'),family=$('#exerciseFamily').value,visible=exercises.map((x,i)=>({...x,index:i})).filter(x=>(family==='all'||x.family===family)&&(!term||`${x.name} ${x.kind} ${x.goal}`.toLocaleLowerCase('fr').includes(term)));$('#exerciseCount').textContent=`${visible.length} exercice${visible.length>1?'s':''} illustré${visible.length>1?'s':''}`;$('#exerciseCards').innerHTML=visible.map(x=>{const p=exercisePrescription(x);return `<button class="exercise-card" data-exercise="${x.index}"><span class="exercise-art sheet-${x.sheet} art-${x.art}" aria-hidden="true"></span><b>${x.name}</b><small>${x.kind} · ${exerciseFormat(x)} · repos ${p.rest}s · ≈ ${p.minutes} min</small><em>${x.cue}</em></button>`;}).join('')||'<div class="empty-state">Aucun exercice ne correspond à cette recherche.</div>'; $('#sessionExerciseList').innerHTML=sessionExercises.map((x,i)=>{const p=exercisePrescription(x);return `<div class="prepared-exercise">${exerciseVisual(x,'prepared-thumb')}<span class="prepared-exercise-copy"><b>${x.name}</b><small>${exerciseFormat(x)}${x.load?` · ${x.load} kg`:''} · repos ${p.rest}s · ≈ ${p.minutes} min</small></span><button type="button" data-remove-exercise="${i}" aria-label="Retirer ${x.name}">×</button></div>`;}).join(''); }
