$('#missionSteps').onclick=e=>{const action=e.target.closest('[data-mission-action]')?.dataset.missionAction;if(!action)return;const map={morning:['focus','.morning-panel'],focus:['focus','.focus-panel'],athlete:['athlete','.athlete-companion'],nutrition:['athlete','.nutrition-panel'],life:['dashboard','.life-panel'],evening:['focus','.reflection-panel']};const target=map[action];if(target)goToSection(target[0],target[1]);};$('#missionPlanWeek').onclick=()=>goToSection('athlete','.planning-panel');
$('#todayCoachAction').onclick=e=>{const action=e.currentTarget.dataset.action;if(action==='recovery'){goToSection('athlete','.recovery-panel');return;}if(action==='planned'){const plan=state.plans.find(p=>p.id===Number(e.currentTarget.dataset.planId));if(plan)startPlannedWorkout(plan);return;}if(action==='mobility'){openGuidedWorkout({title:'Mobilité & retour au calme',duration:20,why:'Une séance courte pour entretenir la mobilité, respirer et laisser la récupération remonter.',exercises:[{name:'Dead bug',sets:2,reps:8},{name:'Bird dog',sets:2,reps:8},{name:'Squat cosaque',sets:2,reps:6},{name:'Gainage planche',sets:2,reps:20,unit:'sec'}]});return;}const workout=programs[state.activeProgram].workouts[Number(e.currentTarget.dataset.workoutIndex)||0];if(workout)openGuidedWorkout(workout);};
$('#todayCoachSecondary').onclick=()=>goToSection('athlete','.planning-panel');
document.querySelector('.focus-presets').onclick=e=>{const mins=Number(e.target.dataset.focus);if(!mins)return;focusDuration=mins;remaining=mins*60;paintTimer();$('#focusInsight').textContent=`Bloc de ${mins} minutes préparé. Un seul objectif, puis une vraie pause.`;};
$('#agendaDate').value=localDate();$('#agendaForm').onsubmit=e=>{e.preventDefault();state.agenda.push(normalizeAgendaItem({id:Date.now(),title:$('#agendaTitle').value.trim(),date:$('#agendaDate').value,time:$('#agendaTime').value,kind:$('#agendaKind').value}));e.target.reset();$('#agendaDate').value=localDate();save();renderCommandCenter();};
$('#weekCalendar').onclick=e=>{const id=Number(e.target.closest('[data-toggle-agenda]')?.dataset.toggleAgenda),item=state.agenda.find(a=>a.id===id);if(!item)return;state.agenda=state.agenda.map(a=>a.id===id?{...a,completed:!a.completed}:a);save();renderCommandCenter();renderDailyCompass();};
$('#exportIcs').onclick=()=>download('level-up-irl-agenda.ics','text/calendar',buildIcs(state.agenda));
$('#openCalendarPage').onclick=()=>{$('#calendarPage').hidden=false;renderMonthCalendar();}; $('#closeCalendarPage').onclick=()=>$('#calendarPage').hidden=true; $('#previousMonth').onclick=()=>{calendarCursor.setMonth(calendarCursor.getMonth()-1);renderMonthCalendar();}; $('#nextMonth').onclick=()=>{calendarCursor.setMonth(calendarCursor.getMonth()+1);renderMonthCalendar();}; $('#todayMonth').onclick=()=>{calendarCursor=new Date();renderMonthCalendar();}; $('#exportIcsPage').onclick=()=>$('#exportIcs').click();
$('#openUltraPage').onclick=()=>{$('#ultraPage').hidden=false;renderUltraPage();}; $('#closeUltraPage').onclick=()=>$('#ultraPage').hidden=true;
$('#saveUltraPlan').onclick=()=>{state.ultraPlan={distance:Math.max(0,Number($('#ultraBaseDistance').value)||0),elevation:Math.max(0,Number($('#ultraBaseElevation').value)||0),longRun:Math.max(0,Number($('#ultraBaseLongRun').value)||0)};save();renderUltraPage();};
$('#calendarAgendaDate').value=localDate(); $('#calendarAgendaForm').onsubmit=e=>{e.preventDefault();const repeat=Number($('#calendarRepeat').value),base=new Date(`${$('#calendarAgendaDate').value}T12:00:00`);for(let i=0;i<=repeat;i++){const d=new Date(base);d.setDate(d.getDate()+i*7);state.agenda.push(normalizeAgendaItem({id:Date.now()+i,title:$('#calendarAgendaTitle').value.trim(),date:dateKey(d),time:$('#calendarAgendaTime').value,kind:$('#calendarAgendaKind').value}));}e.target.reset();$('#calendarAgendaDate').value=localDate();save();renderCommandCenter();renderMonthCalendar();};
$('#studyStart').value=localDate();
$('#studyPlanForm').onsubmit=e=>{e.preventDefault();const weekdays=[...document.querySelectorAll('#studyDays input:checked')].map(i=>Number(i.value));const events=planStudySessions({title:$('#studyTitle').value.trim()||'Révision',time:$('#studyTime').value||'17:30',durationMin:Number($('#studyDuration').value)||45,weekdays,startDate:$('#studyStart').value||localDate(),examDate:$('#studyExam').value,baseId:Date.now()});if(!events.length){$('#studyPlanStatus').textContent='Choisis au moins un jour, et une date d’examen postérieure au début.';return;}state.agenda=mergePlannedEvents(state.agenda,events).map(normalizeAgendaItem);save();renderCommandCenter();renderMonthCalendar();renderDailyCompass();$('#studyPlanStatus').textContent=`${events.length} créneau${events.length>1?'x':''} de révision jusqu'au ${$('#studyExam').value.split('-').reverse().join('/')} · régénérable sans doublon.`;};
$('#monthCalendar').onclick=e=>{const id=Number(e.target.dataset.deleteAgenda);if(!id)return;if(confirm('Supprimer ce bloc du calendrier ?')){const item=state.agenda.find(a=>a.id===id);state.agenda=state.agenda.filter(a=>a.id!==id);if(item?.planId)state.plans=state.plans.filter(p=>p.id!==item.planId);save();renderCommandCenter();renderMonthCalendar();renderGrowth();renderDailyCompass();renderTrainingCompanion();}};
const pageGroups={dashboard:['.player-card','.mission-control','.stats-grid','.command-grid','.day-compass-panel','.quest-section'],athlete:['.athlete-header','.athlete-companion','.training-grid','.exercise-library','.personal-trends'],focus:['.two-columns','.morning-panel','.reflection-panel','.achievements','.reminder-panel']}; function showPage(page){Object.entries(pageGroups).forEach(([name,selectors])=>selectors.forEach(s=>document.querySelectorAll(s).forEach(el=>el.classList.toggle('app-page-hidden',name!==page))));$('.hero').classList.toggle('app-page-hidden',page!=='dashboard');document.querySelectorAll('[data-page]').forEach(b=>b.classList.toggle('active',b.dataset.page===page));let title=document.querySelector('.page-title');if(page==='dashboard'){title?.remove();return;}if(!title){title=document.createElement('div');title.className='page-title';$('.app-nav').after(title);} title.innerHTML=page==='athlete'?'<p class="eyebrow">ENTRAÎNEMENT & PROGRESSION</p><h2>Mode Athlète</h2><p>Construis, mesure et récupère.</p>':'<p class="eyebrow">ESPRIT & ÉQUILIBRE</p><h2>Focus & Vie</h2><p>Protège ton attention et ton énergie.</p>';}; document.querySelectorAll('[data-page]').forEach(b=>b.onclick=()=>showPage(b.dataset.page));
let remaining = 25*60, focusDuration=25, interval;function paintTimer(){const m=Math.floor(remaining/60),s=remaining%60;$('#timer').textContent=`${m}:${String(s).padStart(2,'0')}`;}function finishFocusBlock(){const id=Date.now();state.focusSessions.push({id,date:localDate(),minutes:focusDuration,task:state.focusTask||'Bloc de concentration'});state.focusSessions=state.focusSessions.slice(-300);remaining=focusDuration*60;state.timerRuns++;pendingFocusReview=id;award(25,'focus');$('#timerButton').textContent='Session terminée ✓';setTimeout(()=>{$('#timerButton').textContent='Lancer la session';if(!$('#focusReviewDialog').open)$('#focusReviewDialog').showModal();},350);paintTimer();}$('#timerButton').onclick=()=>{if(interval){clearInterval(interval);interval=null;$('#timerButton').textContent='Reprendre';return;}$('#timerButton').textContent='Pause';interval=setInterval(()=>{remaining--;paintTimer();if(remaining<=0){clearInterval(interval);interval=null;finishFocusBlock();}},1000)};$('#timerReset').onclick=()=>{clearInterval(interval);interval=null;remaining=focusDuration*60;paintTimer();$('#timerButton').textContent='Lancer la session';};$('#focusFullscreen').onclick=()=>{const panel=$('.focus-panel');if(document.fullscreenElement)document.exitFullscreen?.();else panel.requestFullscreen?.();};document.addEventListener('fullscreenchange',()=>{$('#focusFullscreen').textContent=document.fullscreenElement?'Quitter plein écran':'Plein écran';});$('#closeFocusReview').onclick=()=>$('#focusReviewDialog').close();$('#saveFocusReview').onclick=()=>{const outcome=$('#focusReviewOutcome').value.trim(),next=$('#focusReviewNext').value.trim();if(!outcome&&!next){$('#focusReviewOutcome').focus();return;}state.focusReviews.push({id:Date.now(),sessionId:pendingFocusReview,date:localDate(),outcome,next});state.focusReviews=state.focusReviews.slice(-300);pendingFocusReview=null;$('#focusReviewOutcome').value='';$('#focusReviewNext').value='';$('#focusReviewDialog').close();save();renderFocusRitual();renderPersonalTrends();};
async function setupDesktopReminders() { if (!window.desktop) return; $('#desktopNote').textContent = 'Les rappels fonctionnent même lorsque la fenêtre est réduite dans la zone de notification.'; const cfg = await window.desktop.getNotifications(); $('#notificationEnabled').checked = cfg.enabled; $('#reminderOne').value = cfg.times[0] || '09:00'; $('#reminderTwo').value = cfg.times[1] || '18:00'; $('#saveReminders').onclick = async () => { await window.desktop.saveNotifications({ enabled: $('#notificationEnabled').checked, times: [$('#reminderOne').value, $('#reminderTwo').value] }); $('#desktopNote').textContent = '✓ Rappels enregistrés. Ton futur toi te remercie déjà.'; }; $('#testReminder').onclick = () => window.desktop.testNotification(); }
async function offerLocalBackupRestore(){if(savedStateRaw||!window.desktop?.getLocalBackup){automaticBackupReady=true;save();return;}try{const backup=await window.desktop.getLocalBackup();if(backup?.state&&confirm('Une copie locale automatique a été trouvée. Restaurer tes données sur cet appareil ?')){state=normalizeState(backup.state);render();}}catch{}finally{automaticBackupReady=true;save();}}
render();paintTimer();showPage('dashboard');setupDesktopReminders();offerLocalBackupRestore().then(migratePhotosToDisk);setTimeout(()=>{const isNew=!state.onboardingDone&&!state.workouts.length&&!state.focusSessions.length&&!state.lifeGoals.some(Boolean);if(!isNew)return;$('#onboardingGoal').value=state.profile.goal||'recomposition';$('#onboardingLevel').value=state.profile.level||'debutant';$('#onboardingSessions').value=state.goals.sessions||3;$('#onboardingKettlebell').checked=Boolean(state.profile.equipment?.kettlebell);$('#onboardingVest').checked=Boolean(state.profile.equipment?.vest);$('#onboardingBench').checked=Boolean(state.profile.equipment?.bench);$('#onboardingDialog').showModal();},180);
